def line_share_link(text):
    # LINE share ต้องใช้ %0A แทน newline และ encode ให้ถูกต้อง
    encoded = urlquote(text, safe="")
    return "https://line.me/R/msg/text/?" + encoded

def line_notify_owner(message: str):
    """ส่งข้อความแจ้งเจ้าของร้านผ่าน LINE Messaging API"""
    if not LINE_TOKEN or not LINE_USER_ID:
        return False
    try:
        import urllib.request, json as _json
        payload = _json.dumps({
            "to": LINE_USER_ID,
            "messages": [{"type": "text", "text": message}]
        }).encode("utf-8")
        req = urllib.request.Request(
            "https://api.line.me/v2/bot/message/push",
            data=payload,
            headers={
                "Content-Type": "application/json",
                "Authorization": f"Bearer {LINE_TOKEN}"
            },
            method="POST"
        )
        with urllib.request.urlopen(req, timeout=5) as res:
            return res.status == 200
    except Exception as e:
        print(f"LINE notify error: {e}")
        return False

